// export default Navigation;

"use client";
import { useState } from "react";
import Link from "next/link";

export default function Navigation() {
  const [open, setOpen] = useState(false);

  return (
    <header>
      {/* Ticker Section */}
      <div
        style={{
          background: "#581C1E",
          whiteSpace: "nowrap",
          overflow: "hidden",
          display: "flex",
          alignItems: "center",
          height: "40px",
        }}
        className="border-b border-white/10"
      >
        <div
          style={{
            display: "inline-flex",
            animation: "scroll-left 40s linear infinite",
          }}
        >
          <span className="px-4 md:px-8 text-[10px] md:text-[11px] font-bold uppercase tracking-[0.3em] text-white flex items-center">
            Perfect Fit Since 1999 ● India's Premier Ladies Custom Tailor ●
            Quality Stitched Heritage ● Luxury Bespoke ●
          </span>
          <span className="px-4 md:px-8 text-[10px] md:text-[11px] font-bold uppercase tracking-[0.3em] text-white flex items-center">
            Perfect Fit Since 1999 ● India's Premier Ladies Custom Tailor ●
            Quality Stitched Heritage ● Luxury Bespoke ●
          </span>
        </div>
      </div>

      {/* Main Navigation */}
      <nav className="sticky top-0 z-50 bg-blue-950 border-b border-stone-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16 md:h-20">
            {/* Logo */}
            <div className="flex-shrink-0">
              <span className="font-outfit text-xl md:text-2xl font-black tracking-tighter text-rose-100 uppercase">
                <Link href="/">
                  Yogeshwar<span className="text-red-800">.</span>
                </Link>
              </span>
            </div>

            {/* Desktop Menu */}
            <div className="hidden lg:flex items-center space-x-10 text-xs font-bold tracking-[0.1em]">
              <Link
                href="/"
                className="text-rose-50 hover:text-red-400 transition-colors uppercase"
              >
                Home
              </Link>
              <Link
                href="/whyus"
                className="text-rose-50 hover:text-red-400 transition-colors uppercase"
              >
                Why Us
              </Link>
              <Link
                href="/outfits"
                className="text-rose-50 hover:text-red-400 transition-colors uppercase"
              >
                Outfits
              </Link>
              <Link
                href="/contact"
                className="text-rose-50 hover:text-red-400 transition-colors uppercase"
              >
                Contact
              </Link>

              {/* Account Dropdown */}
              <div className="relative group cursor-pointer">
                <button className="text-rose-50 flex items-center gap-1 hover:text-red-400 uppercase tracking-widest outline-none">
                  Account{" "}
                  <span className="material-symbols-outlined text-sm">
                    expand_more
                  </span>
                </button>
                <div className="absolute right-0 top-full pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 transform translate-y-2 group-hover:translate-y-0">
                  <div className="w-52 bg-white shadow-xl rounded-2xl p-2 border border-stone-100">
                    <Link
                      href="/signup"
                      className="block px-4 py-2 text-xs hover:text-rose-50 hover:bg-red-800 font-bold text-red-800 tracking-widest rounded-xl transition"
                    >
                      Signup
                    </Link>
                    <Link
                      href="/orders"
                      className="block px-4 py-2 text-xs hover:text-rose-50 hover:bg-red-800 font-bold text-red-800 tracking-widest rounded-xl transition"
                    >
                      Login
                    </Link>
                    <Link
                      href="/admin"
                      className="block px-4 py-2 text-xs hover:text-rose-50 hover:bg-red-800 font-bold text-red-800 tracking-widest rounded-xl transition"
                    >
                      Admin
                    </Link>
                    <button
                      href="/dashboard"
                      className="block px-4 py-2 text-xs hover:text-rose-50 hover:bg-red-800 font-bold text-red-800 tracking-widest rounded-xl transition"
                    >
                      Logout
                    </button>
                  </div>
                </div>

                {/* second Droupdown */}
              </div>

              {/* CTA Button */}
              <Link
                href="/contact"
                className="bg-rose-50 text-blue-950 px-8 py-3.5 rounded-full text-xs font-bold uppercase tracking-widest hover:bg-red-800 hover:text-white transition-all shadow-lg active:scale-95"
              >
                Book Visit
              </Link>
            </div>

            {/* Mobile Menu Toggle */}
            <button
              onClick={() => setOpen(!open)}
              className="lg:hidden p-2 text-rose-100"
            >
              <span className="material-symbols-outlined text-3xl">
                {open ? "close" : "menu"}
              </span>
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        {open && (
          <div className="lg:hidden bg-blue-950 border-t border-stone-100 px-5 py-6 space-y-5 shadow-2xl overflow-y-auto max-h-[calc(100vh-80px)]">
            <Link
              href="/"
              className="block text-xs font-bold uppercase tracking-widest text-rose-100"
            >
              Home
            </Link>
            <Link
              href="/about"
              className="block text-xs font-bold uppercase tracking-widest text-rose-100"
            >
              Why Us
            </Link>
            <Link
              href="/outfits"
              className="block text-xs font-bold uppercase tracking-widest text-rose-100"
            >
              Outfits
            </Link>
            <Link
              href="/contact"
              className="block text-xs font-bold uppercase tracking-widest text-rose-100"
            >
              Contact
            </Link>

            <hr className="border-stone-100/20" />

            <div className="space-y-3">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">
                Account Settings
              </p>
              <Link
                href="/profile"
                className="block text-xs font-bold text-rose-100 tracking-widest"
              >
                Profile
              </Link>
              <Link
                href="/orders"
                className="block text-xs font-bold text-rose-100 tracking-widest"
              >
                My Orders
              </Link>
              <Link
                href="/dashboard"
                className="block text-xs font-bold text-rose-100 tracking-widest"
              >
                Dashboard
              </Link>
            </div>

            <Link
              href="/contact"
              className="block w-full bg-rose-50 text-blue-950 hover:bg-red-800 hover:text-white text-center py-3.5 rounded-xl text-xs font-bold uppercase tracking-widest active:scale-95 transition-all"
            >
              Book Visit
            </Link>
          </div>
        )}
      </nav>
    </header>
  );
}
